// Java 25 exam prep - Stream partitioning
// Learn: split stream elements into true and false partitions.
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

Map<Boolean, List<Task>> byDone = tasks.stream()
    // partitioningBy always returns Boolean keys.
    .collect(Collectors.partitioningBy(Task::done));

Map<Boolean, Long> doneCounts = tasks.stream()
    .collect(Collectors.partitioningBy(Task::done, Collectors.counting()));
System.out.println(byDone.get(false).size() + " pending");
System.out.println(doneCounts.get(true) + " finished");
